#!/bin/bash
# Generate a synthetic 10,000+ line Klar program for compilation benchmarks.
# Output: benchmarks/compile/synthetic_10k.kl

OUT="benchmarks/compile/synthetic_10k.kl"

cat > "$OUT" << 'HEADER'
// Synthetic benchmark: ~10,000 lines of valid Klar code
// Auto-generated by generate_synthetic.sh

HEADER

# Generate 200 arithmetic functions (~20 lines each = 4000 lines)
for i in $(seq 1 200); do
    cat >> "$OUT" << EOF
fn compute_${i}(a: i32, b: i32) -> i32 {
    var result: i32 = a + b
    let c: i32 = a * 2
    let d: i32 = b * 3
    if c > d {
        result = c - d
    } else {
        result = d - c
    }
    var acc: i32 = 0
    for i: i32 in 0..10 {
        acc = acc + i + result
    }
    let x: i32 = acc + c
    let y: i32 = x - d + result
    let z: i32 = y * 2 + a - b
    return z + ${i}
}

EOF
done

# Generate 100 struct functions (~25 lines each = 2500 lines)
for i in $(seq 1 100); do
    cat >> "$OUT" << EOF
struct Data_${i} { a: i32, b: i32, c: f64 }

fn process_data_${i}(d: Data_${i}) -> i32 {
    var sum: i32 = d.a + d.b
    if sum > 100 {
        sum = sum - 50
    } else if sum > 50 {
        sum = sum + 10
    } else {
        sum = sum * 2
    }
    var acc: i32 = 0
    for j: i32 in 0..5 {
        acc = acc + sum + j
    }
    let result: i32 = acc + d.a
    return result + ${i}
}

fn make_data_${i}(x: i32) -> Data_${i} {
    return Data_${i} { a: x, b: x + ${i}, c: 1.0 }
}

EOF
done

# Generate 130 match/enum-style functions (~20 lines each = 2600 lines)
for i in $(seq 1 130); do
    cat >> "$OUT" << EOF
fn classify_${i}(n: i32) -> i32 {
    var result: i32 = 0
    if n > 1000 {
        result = 3
    } else if n > 100 {
        result = 2
    } else if n > 10 {
        result = 1
    } else {
        result = 0
    }
    let adjusted: i32 = result + n
    var total: i32 = 0
    for k: i32 in 0..result {
        total = total + k + adjusted
    }
    return total + ${i}
}

EOF
done

# Generate 80 string-returning functions (~12 lines each = 960 lines)
for i in $(seq 1 80); do
    cat >> "$OUT" << EOF
fn format_${i}(n: i32) -> string {
    var result: string = "value_${i}: "
    if n > 0 {
        result = result + "positive"
    } else if n < 0 {
        result = result + "negative"
    } else {
        result = result + "zero"
    }
    return result
}

EOF
done

# Main function that calls everything
cat >> "$OUT" << 'MAIN_START'
fn main() -> i32 {
    var total: i32 = 0
MAIN_START

for i in $(seq 1 200); do
    echo "    total = total + compute_${i}(${i}, ${i} + 1)" >> "$OUT"
done

for i in $(seq 1 100); do
    echo "    let d_${i}: Data_${i} = make_data_${i}(${i})" >> "$OUT"
    echo "    total = total + process_data_${i}(d_${i})" >> "$OUT"
done

for i in $(seq 1 130); do
    echo "    total = total + classify_${i}(${i} * 10)" >> "$OUT"
done

cat >> "$OUT" << 'MAIN_END'
    return total
}
MAIN_END

LINES=$(wc -l < "$OUT")
echo "Generated $OUT ($LINES lines)"
